svg.script:
const GRAVITY = 1.3;
const BOUNCE = 0.55;
const FLOOR_Y = 160;
const SHADOW_Y = 195;
const XHTML_NS = 'http://www.w3.org/1999/xhtml';

class DiePhysics {
  constructor(index) {
    this.index = index;
    this.posEl = document.getElementById(`pos-${index}`);
    this.rotEl = document.getElementById(`rot-${index}`);
    this.shadowEl = document.getElementById(`shadow-${index}`);
    this.size = 80;
    this.radius = 45;
    this.isGrabbed = false;
    this.roll(false);
  }

  roll(isClick) {
    this.settling = false;
    this.isGrabbed = false;
    if (isClick) {
      this.y -= 10;
    } else {
      this.x = (this.index - 1) * 120 + (Math.random() - 0.5) * 50;
      this.y = -700 - Math.random() * 400;
      this.z = (Math.random() - 0.5) * 100;
      this.vx = (Math.random() - 0.5) * 15;
      this.vy = Math.random() * 10;
      this.vz = (Math.random() - 0.5) * 15;
      this.rx = Math.random() * 360;
      this.ry = Math.random() * 360;
      this.rz = Math.random() * 360;
      this.vrx = (Math.random() - 0.5) * 50;
      this.vry = (Math.random() - 0.5) * 50;
      this.vrz = (Math.random() - 0.5) * 50;
    }
  }

  update() {
    if (this.isGrabbed) return;
    if (!this.settling) {
      this.vy += GRAVITY;
      this.x += this.vx;
      this.y += this.vy;
      this.z += this.vz;
      this.rx += this.vrx;
      this.ry += this.vry;
      this.rz += this.vrz;
      this.vx *= 0.995;
      this.vz *= 0.995;

      if (this.y > FLOOR_Y) {
        this.y = FLOOR_Y;
        this.vy *= -BOUNCE;
        this.vx *= 0.82;
        this.vz *= 0.82;
        this.vrx *= 0.82;
        this.vry *= 0.82;
        this.vrz *= 0.82;
        if (Math.abs(this.vy) > 2) {
          this.vrx += (Math.random() - 0.5) * 25;
          this.vry += (Math.random() - 0.5) * 25;
        }
      }

      const boundsX = 400;
      const boundsZ = 280;
      if (this.x < -boundsX) { this.x = -boundsX; this.vx *= -BOUNCE; this.vry += 15; }
      if (this.x > boundsX) { this.x = boundsX; this.vx *= -BOUNCE; this.vry -= 15; }
      if (this.z < -boundsZ) { this.z = -boundsZ; this.vz *= -BOUNCE; this.vrx -= 15; }
      if (this.z > boundsZ) { this.z = boundsZ; this.vz *= -BOUNCE; this.vrx += 15; }

      const speed = Math.abs(this.vx) + Math.abs(this.vy) + Math.abs(this.vz) +
        Math.abs(this.vrx) + Math.abs(this.vry) + Math.abs(this.vrz);

      if (speed < 2.0 && Math.abs(this.y - FLOOR_Y) < 2) {
        this.settling = true;
        this.vx = this.vy = this.vz = 0;
        this.vrx = this.vry = this.vrz = 0;
        this.y = FLOOR_Y;
      }
    } else {
      this.rx += (Math.round(this.rx / 90) * 90 - this.rx) * 0.15;
      this.ry += (Math.round(this.ry / 90) * 90 - this.ry) * 0.15;
      this.rz += (Math.round(this.rz / 90) * 90 - this.rz) * 0.15;
    }
  }

  draw() {
    this.posEl.style.transform = `translate3d(${this.x}px, ${this.y}px, ${this.z}px)`;
    this.rotEl.style.transform = `rotateX(${this.rx}deg) rotateY(${this.ry}deg) rotateZ(${this.rz}deg)`;
    const distFromFloor = Math.max(0, FLOOR_Y - this.y);
    const scale = Math.max(0.1, 1 - distFromFloor / 300);
    let opacity = Math.max(0, 0.7 - distFromFloor / 400);
    if (this.isGrabbed) opacity = 0;
    this.shadowEl.style.transform = `translate3d(${this.x}px, ${SHADOW_Y}px, ${this.z}px) rotateX(90deg) scale(${scale})`;
    this.shadowEl.style.opacity = opacity;
  }
}

class SketchMonkey {
  constructor() {
    this.pivotEl = document.getElementById('monkey-pivot');
    this.rotEl = document.getElementById('monkey-rot');
    this.shadowEl = document.getElementById('monkey-shadow');
    this.state = 'IDLE';
    this.radius = 920;
    this.pivotY = -750;
    this.z = 0;
    this.swingAngle = 0;
    this.speed = 0;
  }

  trigger() {
    if (this.state !== 'IDLE') return;
    this.state = 'SWINGING';
    const fromRight = Math.random() > 0.5;
    this.swingAngle = fromRight ? (Math.PI / 2.1) : -(Math.PI / 2.1);
    this.speed = 0;
    this.pivotEl.style.display = 'block';
    this.hasHit = false;
    this.z = (Math.random() - 0.5) * 80;
    this.pivotEl.style.transform = `translate3d(0px, ${this.pivotY}px, ${this.z}px)`;
  }

  update(diceArr) {
    if (this.state === 'SWINGING') {
      const angularGravity = 0.0035;
      const acceleration = -angularGravity * Math.sin(this.swingAngle);
      this.speed += acceleration;
      this.speed *= 0.995;
      this.swingAngle += this.speed;
      this.rotEl.style.transform = `rotateZ(${this.swingAngle}rad)`;

      const monkeyX = Math.sin(this.swingAngle) * this.radius;
      const monkeyY = this.pivotY + Math.cos(this.swingAngle) * this.radius;
      const shadowOpacity = Math.max(0, 0.7 - Math.abs(monkeyX) / 500);
      this.shadowEl.style.opacity = shadowOpacity;
      this.shadowEl.style.transform = `translate3d(${monkeyX}px, ${SHADOW_Y}px, ${this.z}px) rotateX(90deg) scale(${1 - Math.abs(monkeyX) / 1000})`;

      if (!this.hasHit && Math.abs(this.swingAngle) < 0.2) {
        this.batDice(diceArr, monkeyX, monkeyY);
        this.hasHit = true;
      }

      if (this.hasHit && Math.abs(this.speed) < 0.003 && Math.abs(this.swingAngle) > 1.2) {
        this.state = 'IDLE';
        this.pivotEl.style.display = 'none';
        this.shadowEl.style.opacity = 0;
      }
    }
  }

  batDice(diceArr, mx, my) {
    diceArr.forEach(d => {
      const dx = d.x - mx;
      const dz = d.z - this.z;
      const dist = Math.max(1, Math.sqrt(dx * dx + dz * dz));
      if (dist < 320 && d.y > FLOOR_Y - 100) {
        d.settling = false;
        d.isGrabbed = false;
        d.y -= 15;
        const force = 1200 / (dist + 20);
        d.vx = (dx / dist) * force + (this.speed * 500) + (Math.random() - 0.5) * 20;
        d.vy = -20 - Math.random() * 25;
        d.vz = (dz / dist) * force + (Math.random() - 0.5) * 20;
        d.vrx = (Math.random() - 0.5) * 150;
        d.vry = (Math.random() - 0.5) * 150;
        d.vrz = (Math.random() - 0.5) * 150;
      }
    });
  }
}

class SketchCat {
  constructor() {
    this.posEl = document.getElementById('cat-pos');
    this.svgEl = document.getElementById('cat-svg');
    this.flipGroup = document.getElementById('cat-flip-group');
    this.shadowEl = document.getElementById('cat-shadow');
    this.state = 'IDLE';
    this.timer = 0;
    this.speed = 3.5;
  }

  trigger() {
    if (this.state !== 'IDLE') return;
    this.side = Math.random() > 0.5 ? 'left' : 'right';
    this.startX = this.side === 'left' ? -650 : 650;
    this.targetX = this.side === 'left' ? -90 - Math.random() * 40 : 90 + Math.random() * 40;
    this.x = this.startX;
    this.y = FLOOR_Y;
    this.z = (Math.random() - 0.5) * 180;

    if (this.side === 'right') {
      this.flipGroup.setAttribute('transform', 'scale(-1, 1) translate(-140, 0)');
    } else {
      this.flipGroup.setAttribute('transform', 'scale(1, 1) translate(0, 0)');
    }

    this.state = 'WALKING_IN';
    this.svgEl.classList.add('walking');
    this.posEl.style.display = 'block';
  }

  update(diceArr) {
    if (this.state === 'WALKING_IN') {
      if (this.side === 'left') {
        this.x += this.speed;
        if (this.x >= this.targetX) this.startAttack();
      } else {
        this.x -= this.speed;
        if (this.x <= this.targetX) this.startAttack();
      }
    } else if (this.state === 'SWIPING') {
      this.timer--;
      if (this.timer === 25) this.svgEl.classList.add('swiping');
      if (this.timer === 12) this.batDice(diceArr);
      if (this.timer <= 0) {
        this.state = 'WALKING_OUT';
        this.svgEl.classList.remove('swiping');
        this.svgEl.classList.add('walking');
        if (this.side === 'left') {
          this.flipGroup.setAttribute('transform', 'scale(-1, 1) translate(-140, 0)');
        } else {
          this.flipGroup.setAttribute('transform', 'scale(1, 1) translate(0, 0)');
        }
      }
    } else if (this.state === 'WALKING_OUT') {
      if (this.side === 'left') {
        this.x -= this.speed;
        if (this.x < -650) this.reset();
      } else {
        this.x += this.speed;
        if (this.x > 650) this.reset();
      }
    }
  }

  startAttack() {
    this.state = 'SWIPING';
    this.svgEl.classList.remove('walking');
    this.timer = 40;
  }

  reset() {
    this.state = 'IDLE';
    this.posEl.style.display = 'none';
    this.svgEl.classList.remove('walking');
    this.shadowEl.style.opacity = 0;
  }

  batDice(diceArr) {
    const pawX = this.side === 'left' ? this.x + 95 : this.x + 45;
    diceArr.forEach(d => {
      const dx = d.x - pawX;
      const dz = d.z - this.z;
      const dist = Math.max(1, Math.sqrt(dx * dx + dz * dz));
      if (dist < 220 && !d.isGrabbed) {
        d.settling = false;
        d.y -= 8;
        const force = 900 / (dist + 5);
        const dirX = this.side === 'left' ? 1 : -1;
        d.vx = (dx / dist) * force + (dirX * 12) + (Math.random() - 0.5) * 15;
        d.vy = -12 - Math.random() * 20;
        d.vz = (dz / dist) * force + (Math.random() - 0.5) * 20;
        d.vrx = (Math.random() - 0.5) * 100;
        d.vry = (Math.random() - 0.5) * 100;
        d.vrz = (Math.random() - 0.5) * 100;
      }
    });
  }

  draw() {
    if (this.state === 'IDLE') return;
    this.posEl.style.transform = `translate3d(${this.x}px, ${this.y}px, ${this.z}px)`;
    this.shadowEl.style.opacity = 0.6;
    this.shadowEl.style.transform = `translate3d(${this.x + 60}px, ${SHADOW_Y}px, ${this.z}px) rotateX(90deg)`;
  }
}

class SketchHawk {
  constructor() {
    this.posEl = document.getElementById('hawk-pos');
    this.rotEl = document.getElementById('hawk-rot');
    this.shadowEl = document.getElementById('hawk-shadow');
    this.state = 'IDLE';
    this.angle = 0;
  }

  trigger(diceArr) {
    if (this.state !== 'IDLE') return;
    const available = diceArr.filter(d => !d.isGrabbed && d.y >= FLOOR_Y - 5);
    if (available.length === 0) return;
    this.targetDie = available[Math.floor(Math.random() * available.length)];
    this.targetDie.settling = false;
    this.grabX = this.targetDie.x;
    this.grabZ = this.targetDie.z;
    this.y = -900;
    this.r = 300 + Math.random() * 150;
    this.angle = Math.random() * Math.PI * 2;
    this.orbitSpeed = 0.05 + Math.random() * 0.02;
    this.lastX = 0;
    this.lastZ = 0;
    this.state = 'CIRCLING_DOWN';
    this.posEl.style.display = 'block';
  }

  update() {
    if (this.state === 'IDLE') return;
    this.angle += this.orbitSpeed;
    if (this.state === 'CIRCLING_DOWN') {
      this.y += 18;
      this.r += (0 - this.r) * 0.04;
      if (this.y >= FLOOR_Y - 50) {
        this.y = FLOOR_Y - 50;
        this.state = 'GRABBING';
        this.targetDie.isGrabbed = true;
        this.targetDie.settling = false;
      }
    } else if (this.state === 'GRABBING') {
      this.state = 'LIFTING';
    } else if (this.state === 'LIFTING') {
      this.y -= 12;
      this.r += 2.5;
      this.orbitSpeed = 0.03;
      if (this.targetDie && this.targetDie.isGrabbed) {
        this.targetDie.x = this.x;
        this.targetDie.y = this.y + 40;
        this.targetDie.z = this.z;
        this.targetDie.rx += 10;
        this.targetDie.ry += 25;
      }
      if (this.y < -350 - Math.random() * 200) {
        this.state = 'DROPPING';
      }
    } else if (this.state === 'DROPPING') {
      if (this.targetDie && this.targetDie.isGrabbed) {
        this.targetDie.isGrabbed = false;
        const dx = this.x - this.lastX;
        const dz = this.z - this.lastZ;
        this.targetDie.vx = dx * 1.5;
        this.targetDie.vz = dz * 1.5;
        this.targetDie.vy = 5;
      }
      this.state = 'FLYING_AWAY';
    } else if (this.state === 'FLYING_AWAY') {
      this.y -= 25;
      this.r += 8;
      if (this.y < -1200) {
        this.state = 'IDLE';
        this.posEl.style.display = 'none';
        this.shadowEl.style.opacity = 0;
      }
    }
    this.lastX = this.x;
    this.lastZ = this.z;
    this.x = this.grabX + Math.cos(this.angle) * this.r;
    this.z = this.grabZ + Math.sin(this.angle) * this.r;
  }

  draw() {
    if (this.state === 'IDLE') return;
    const dx = this.x - this.lastX;
    const dz = this.z - this.lastZ;
    const flightAngle = Math.atan2(dz, dx) * 180 / Math.PI;
    this.posEl.style.transform = `translate3d(${this.x}px, ${this.y}px, ${this.z}px)`;
    this.rotEl.style.transform = `rotateY(${-flightAngle}deg) rotateZ(12deg) rotateX(10deg)`;
    const shadowOpacity = Math.max(0, 0.5 - (FLOOR_Y - this.y) / 1000);
    const shadowScale = Math.max(0.1, 1 - (FLOOR_Y - this.y) / 800);
    this.shadowEl.style.opacity = shadowOpacity;
    this.shadowEl.style.transform = `translate3d(${this.x}px, ${SHADOW_Y}px, ${this.z}px) rotateX(90deg) scale(${shadowScale})`;
  }
}

const dice = [new DiePhysics(0), new DiePhysics(1), new DiePhysics(2)];
const cat = new SketchCat();
const monkey = new SketchMonkey();
const hawk = new SketchHawk();

function resolveCollisions() {
  for (let i = 0; i < dice.length; i++) {
    for (let j = i + 1; j < dice.length; j++) {
      const d1 = dice[i];
      const d2 = dice[j];
      if (d1.isGrabbed || d2.isGrabbed) continue;
      const dx = d2.x - d1.x;
      const dy = d2.y - d1.y;
      const dz = d2.z - d1.z;
      const dist = Math.sqrt(dx * dx + dy * dy + dz * dz);
      const minDist = d1.radius + d2.radius;
      if (dist < minDist && dist > 0.1) {
        const overlap = minDist - dist;
        const nx = dx / dist;
        const ny = dy / dist;
        const nz = dz / dist;
        d1.x -= nx * overlap * 0.5;
        d1.y -= ny * overlap * 0.5;
        d1.z -= nz * overlap * 0.5;
        d2.x += nx * overlap * 0.5;
        d2.y += ny * overlap * 0.5;
        d2.z += nz * overlap * 0.5;
        const dvx = d1.vx - d2.vx;
        const dvy = d1.vy - d2.vy;
        const dvz = d1.vz - d2.vz;
        const p = (nx * dvx + ny * dvy + nz * dvz) * 1.2;
        d1.vx -= p * nx;
        d1.vy -= p * ny;
        d1.vz -= p * nz;
        d2.vx += p * nx;
        d2.vy += p * ny;
        d2.vz += p * nz;
        d1.settling = false;
        d2.settling = false;
      }
    }
  }

  if (cat.state !== 'IDLE') {
    const catCX = cat.x + 70;
    for (let i = 0; i < dice.length; i++) {
      const d = dice[i];
      if (d.isGrabbed) continue;
      const dx = d.x - catCX;
      const dz = d.z - cat.z;
      const dist = Math.max(1, Math.sqrt(dx * dx + dz * dz));
      const minDist = d.radius + 50;
      if (dist < minDist && d.y > FLOOR_Y - 90) {
        const overlap = minDist - dist;
        const nx = dx / dist;
        const nz = dz / dist;
        d.x += nx * overlap;
        d.z += nz * overlap;
        d.vx += nx * 6;
        d.vz += nz * 6;
        d.settling = false;
      }
    }
  }
}

let idleFrames = 0;
let frameCount = 0;

function runDirector() {
  frameCount++;
  const isSettled = dice.every(d => d.settling || d.isGrabbed);
  idleFrames = isSettled ? idleFrames + 1 : 0;

  if (idleFrames > 80) {
    if (cat.state === 'IDLE' && monkey.state === 'IDLE' && hawk.state === 'IDLE') {
      const r = Math.random();
      if (r < 0.35) cat.trigger();
      else if (r < 0.70) monkey.trigger();
      else hawk.trigger(dice);
      idleFrames = 0;
    }
  }

  if (Math.random() < 0.0015 && cat.state === 'IDLE' && monkey.state === 'IDLE' && hawk.state === 'IDLE') {
    const r = Math.random();
    if (r < 0.33) cat.trigger();
    else if (r < 0.66) monkey.trigger();
    else hawk.trigger(dice);
  }
}

function animate() {
  runDirector();
  hawk.update();
  monkey.update(dice);
  cat.update(dice);
  dice.forEach(d => d.update());
  resolveCollisions();

  const renderables = [
    { el: dice[0].posEl, z: dice[0].z },
    { el: dice[1].posEl, z: dice[1].z },
    { el: dice[2].posEl, z: dice[2].z },
    { el: cat.posEl, z: cat.state !== 'IDLE' ? cat.z : -9999 },
    { el: monkey.pivotEl, z: monkey.state !== 'IDLE' ? monkey.z : -9999 },
    { el: hawk.posEl, z: hawk.state !== 'IDLE' ? hawk.z : -9999 }
  ];

  renderables.sort((a, b) => b.z - a.z);
  renderables.forEach((obj, i) => {
    if (obj.el) obj.el.style.zIndex = i + 10;
  });

  hawk.draw();
  cat.draw();
  dice.forEach(d => d.draw());
  requestAnimationFrame(animate);
}

requestAnimationFrame(animate);

window.addEventListener('pointerdown', e => {
  const rectSource = document.body || document.documentElement;
  const rect = rectSource.getBoundingClientRect();
  const cx = rect.width / 2;
  const cy = rect.height / 2;
  const clickX = (e.clientX - cx) * 1.1;
  const clickZ = (e.clientY - cy - (FLOOR_Y * 0.3)) * 2.2;

  const ripple = document.createElementNS(XHTML_NS, 'div');
  ripple.className = 'ripple';
  ripple.style.transform = `translate3d(${clickX}px, ${FLOOR_Y}px, ${clickZ}px) rotateX(90deg)`;
  document.getElementById('world').appendChild(ripple);
  setTimeout(() => ripple.remove(), 500);

  dice.forEach(d => {
    if (d.isGrabbed) return;
    const dx = d.x - clickX;
    const dz = d.z - clickZ;
    const dist = Math.max(15, Math.sqrt(dx * dx + dz * dz));
    const force = 2200 / dist;
    d.vx += (dx / dist) * force + (Math.random() - 0.5) * 20;
    d.vz += (dz / dist) * force + (Math.random() - 0.5) * 20;
    d.vy = -10 - (1000 / dist) - Math.random() * 10;
    d.vrx += (Math.random() - 0.5) * 120;
    d.vry += (Math.random() - 0.5) * 120;
    d.vrz += (Math.random() - 0.5) * 120;
    d.settling = false;
    if (d.y >= FLOOR_Y - 5) d.y -= 15;
  });

  idleFrames = 0;
});
